    /* Constructor */
    public NetworkConstructor(String species_tree_newick) {
        _net = Networks.readNetwork(species_tree_newick);
        Networks.removeBinaryNodes(_net);
        System.out.println(_net.toString());
        for (Object o: _net.getLeaves()){
            _species.add(((NetNode) o).getName());
        }
    }

    public NetworkConstructor(String tree_newick, String path){
        this(tree_newick);
        _exact_test = read_exact_test(path);
    }

//    public Map<Tuple3<String, String, String>, Boolean> read_exact_test(String path) {
    public Map<Set<String>, Boolean> read_exact_test(String path) {
//        Map<Tuple3<String, String, String>, Boolean> exact_test = new HashMap<>();
        Map<Set<String>, Boolean> exact_test = new HashMap<>();
        try{
            String s;
            BufferedReader reader = new BufferedReader(new FileReader(path));
            while((s = reader.readLine()) != null) {
//                System.out.println(s);
                if (s.startsWith("\"")){
                    String[] ss = s.split("\",");
                    String[] arr = ss[0].split(",");
//                    Tuple3<String, String, String> triplet = new Tuple3<>(arr[0].substring(3, arr[0].length()-1), arr[1].substring(2, arr[1].length()-1), arr[2].substring(2, arr[2].length()-2));
                    Set<String> triplet = new HashSet<>();
                    triplet.add(arr[0].substring(3, arr[0].length()-1));
                    triplet.add(arr[1].substring(2, arr[1].length()-1));
                    triplet.add(arr[2].substring(2, arr[2].length()-2));

//                    System.out.println(triplet);
                    exact_test.put(triplet, Boolean.parseBoolean(ss[1]));
                }
            }
        }catch (Exception e){

        }
        System.out.println(exact_test.size());
        System.out.println(_species);
        System.out.println(_net);
        return exact_test;
    }

